parameters.jsCode:
const aiResponse = $input.first().json.output;
const jsonMatch = aiResponse.match(/```json\s*([\s\S]*?)\s*```/);

let userText = aiResponse;
let newState = null;

if (jsonMatch) {
    try {
        newState = JSON.parse(jsonMatch[1]);
        // Удаляем JSON из текста для пользователя
        userText = aiResponse.replace(jsonMatch[0], "").trim();
    } catch (e) {
        console.log("Ошибка парсинга JSON");
    }
}

return {
    json: {
        text_for_user: userText,
        new_state: newState,
        chat_id: $('Webhook').first().json.body.chat_id,
    }
};

// Берем первый входящий объект данных
const input = $input.first();

// Извлекаем уровень паники из JSON
const panicLevel = input.json.new_state.panic_level;

const randomValue = Math.random(); // Число от 0 до 1
const probability = 0.25; // 25% шанс на голосовое

let sendVoice = false;

// Если паника на максимуме и "кубик" выпал удачно
if (panicLevel === 5 && randomValue < probability) {
    sendVoice = true;
}

// Возвращаем данные. 
// В n8n v1 мы просто возвращаем объект JSON.
return {
    ...input.json, // Копируем все старые данные (текст, чат_ид и т.д.)
    send_voice: sendVoice // Добавляем наш флаг
};

parameters.query:
UPDATE user_states 
SET state_json = '{{ JSON.stringify($json.new_state) }}'::jsonb 
WHERE chat_id = {{ $json.chat_id }};

