// Проверяем, была ли запущена нода Whisper
const voiceNode = $(('Transcribe a recording'));
const webhookBody = $('Webhook').first().json.body;

let final_text = "";

if (webhookBody.is_voice === "true") {
    // Если это был голос, берем текст из Whisper
    final_text = voiceNode.item.json.text;
} else {
    // Если это текст, берем его из вебхука
    final_text = webhookBody.text;
}

return {
    json: {
        player_text: final_text
    }
};

// Просто извлекаем данные
const base64Data = $input.first().json.choices[0].images[0].image_url.url;
const metadata = $('Parse Output').first().json;

return {
  chat_id: metadata.chat_id,
  text_for_user: metadata.text_for_user,
  image_base64: base64Data.split(';base64,').pop() // Берем только чистый код картинки
};
